// ============================================
// AEVUM — Lead Enrichment & Normalization
// ============================================
const body = $input.first().json.body || $input.first().json;

// Timestamp
const now = new Date();
const timestamp = now.toISOString();
const dateOnly = now.toISOString().split('T')[0];
const timeOnly = now.toTimeString().split(' ')[0];

// Lead-ID generieren
const leadId = 'AV-' + Date.now() + '-' + Math.random().toString(36).substr(2, 5).toUpperCase();

// UTM Parameter extrahieren
const utm_source = body.utm_source || 'direct';
const utm_medium = body.utm_medium || 'none';
const utm_campaign = body.utm_campaign || 'unknown';
const utm_content = body.utm_content || '';
const utm_term = body.utm_term || '';

// Creative ID aus utm_content
const creative_id = body.creative_id || utm_content || 'unknown';

// Funnel Stage
const funnel_stage = 'NEW_LEAD';

// Normalisiertes Lead-Objekt
return [{
  json: {
    // IDs
    lead_id: leadId,

    // Kontakt
    name: body.name || '',
    email: body.email || '',
    phone: body.phone || '',
    company: body.company || '',

    // UTM
    utm_source,
    utm_medium,
    utm_campaign,
    utm_content,
    utm_term,
    creative_id,

    // Meta
    fbclid: body.fbclid || '',
    fbp: body.fbp || '',
    fbc: body.fbc || body.fbclid ? 'fb.1.' + Date.now() + '.' + body.fbclid : '',

    // Journey
    funnel_stage,
    source_page: body.source_page || body.page_url || '',

    // Zeitstempel
    timestamp,
    date: dateOnly,
    time: timeOnly,

    // IP (für CAPI)
    ip_address: body.ip_address || '',
    user_agent: body.user_agent || '',

    // Status
    status: 'Neu',
    priority: 'Normal',

    // Notizen
    notes: body.message || body.notes || ''
  }
}];

